#!/usr/bin/env node
/**
 * Branding guard — fails the build if forbidden authorship strings appear
 * anywhere the product ships from. Developed by Laugh Company
 *
 * Scans: src/, index.html (if present), README.md, package.json.
 * Skips: node_modules, build output, auto-generated integration files,
 *        the routeTree, and a small allow-list for runtime host contracts.
 */
import { readdirSync, readFileSync, statSync, existsSync } from "node:fs";
import { join, relative, sep } from "node:path";
import { fileURLToPath } from "node:url";

const ROOT = join(fileURLToPath(import.meta.url), "..", "..");
const FORBIDDEN = [
  /\blovable\b/i,
  /\bgenerated by\b/i,
  /\bauto-?generated\b/i,
  /\bpowered by ai\b/i,
  /\bmade with ai\b/i,
  /\bopenai\b/i,
];

// Runtime/host contracts and dependency identifiers that MUST stay intact.
// Keep this list tiny and justified — anything else is a violation.
const ALLOW = new Set([
  // Runtime host bridge — external platform contract, isolated to one file.
  "src/lib/error-reporting.ts",
  // Auto-managed integration files (regenerated by the backend tooling).
  "src/integrations/supabase/client.ts",
  "src/integrations/supabase/client.server.ts",
  "src/integrations/supabase/auth-middleware.ts",
  "src/integrations/supabase/auth-attacher.ts",
  "src/integrations/supabase/types.ts",
  // Build config referencing the upstream npm packages by their real names.
  "vite.config.ts",
  "bunfig.toml",
  "package.json",
  "bun.lock",
]);

const SKIP_DIRS = new Set([
  "node_modules",
  ".git",
  "dist",
  "build",
  ".output",
  ".vinxi",
  ".nitro",
  ".lovable",
  ".workspace",
  ".agents",
  ".claude",
]);
const SKIP_FILES = new Set(["routeTree.gen.ts", "tsconfig.tsbuildinfo"]);

const TARGETS = ["src", "README.md", "index.html"];

/** @type {{ file: string; line: number; text: string; match: string }[]} */
const hits = [];

function walk(rel) {
  const abs = join(ROOT, rel);
  if (!existsSync(abs)) return;
  const st = statSync(abs);
  if (st.isDirectory()) {
    for (const name of readdirSync(abs)) {
      if (SKIP_DIRS.has(name) || SKIP_FILES.has(name)) continue;
      walk(join(rel, name));
    }
    return;
  }
  const posix = rel.split(sep).join("/");
  if (ALLOW.has(posix)) return;
  if (!/\.(tsx?|jsx?|css|md|html|json|toml|yml|yaml)$/i.test(rel)) return;
  const content = readFileSync(abs, "utf8");
  const lines = content.split(/\r?\n/);
  for (let i = 0; i < lines.length; i++) {
    for (const rx of FORBIDDEN) {
      const m = lines[i].match(rx);
      if (m) hits.push({ file: posix, line: i + 1, text: lines[i].trim().slice(0, 160), match: m[0] });
    }
  }
}

for (const t of TARGETS) walk(t);

if (hits.length) {
  console.error("\n✖ Branding guard failed — forbidden strings found:\n");
  for (const h of hits) {
    console.error(`  ${h.file}:${h.line}  [${h.match}]  ${h.text}`);
  }
  console.error(`\n${hits.length} violation(s). Update the file(s) or, if a match is a legitimate`);
  console.error("external contract, add the path to ALLOW in scripts/check-branding.mjs\n");
  process.exit(1);
}

console.log("✓ Branding guard passed — no forbidden strings in shipped sources.");
